#!/bin/bash\n\n# yt-dlp skill test suite\n\nTEST_DIR=$(mktemp -d)\ncd "$TEST_DIR"\n\necho "Running yt-dlp skill tests in $TEST_DIR"\n\n# Test 1: Check that the wrapper script exists and is executable\nif [ ! -x "/Users/gbencke/.pi/agent/skills/yt-dlp/bin/yt-dlp" ]; then\n    echo "FAILED: yt-dlp wrapper script not found or not executable"\n    exit 1\nfi\n\n# Test 2: Check that yt-dlp is installed\nif ! command -v yt-dlp &> /dev/null; then\n    echo "WARNING: yt-dlp not installed - integration test skipped"\nelse\n    # Test 3: Basic functionality test - try to get version info\n    output="$(/Users/gbencke/.pi/agent/skills/yt-dlp/bin/yt-dlp --version 2>&1)"\n    exit_code=$?\n\n    if [ $exit_code -eq 0 ] && echo "$output" | grep -E '^\[0-9]+\.[0-9]+\.[0-9]+'; then\n        echo "PASSED: yt-dlp wrapper reports version $output"\n    else\n        echo "FAILED: yt-dlp wrapper failed to return version info"\n        exit 1\n    fi\n\n    # Test 4: Test help command\n    if /Users/gbencke/.pi/agent/skills/yt-dlp/bin/yt-dlp --help &> /dev/null; then\n        echo "PASSED: yt-dlp wrapper supports --help"\n    else\n        echo "FAILED: yt-dlp wrapper failed to execute --help"\n        exit 1\n    fi\nfi\n\n# Test 5: Test invalid URL handling\necho "Testing invalid URL handling..."\noutput="$(/Users/gbencke/.pi/agent/skills/yt-dlp/bin/yt-dlp https://invalid.url 2>&1)"\nexit_code=$?\n\nif [ $exit_code -ne 0 ] && echo "$output" | grep -q -i "invalid"; then\n    echo "PASSED: yt-dlp wrapper correctly handles invalid URLs"\nelse\n    echo "FAILED: yt-dlp wrapper does not properly handle invalid URLs"\n    exit 1\nfi\n\necho "All tests passed!"\nrm -rf "$TEST_DIR"\n
